import { Ref } from '../ref.js';
import { PdfToken } from './token.js';
export class PdfByteOffsetToken extends PdfToken {
    value;
    constructor(value = new Ref(0)) {
        super(new Uint8Array());
        this.value = value;
    }
    resolve() {
        return this.value.resolve();
    }
    update(offset) {
        this.value.update(offset);
    }
}
